```class Solution {
public:
    bool possibleBipartition(int n, vector<vector<int>>& dislikes) {
        vector<int> graph(n, 0);
        for (auto dislike : dislikes) {
            graph[dislike[0]] = graph[dislike[1]] = 1;
        }
        return bipartiteGraph(graph, n);
    }

    bool bipartiteGraph(vector<int>& graph, int n) {
        vector<int> oddVertices(n);
        for (int i = 0; i < n; i++) {
            if (graph[i] == 0) {
                oddVertices[i] = 1;
            }
        }
        for (int i = 0; i < n; i++) {
            if (oddVertices[i]) {
                return false;
            }
        }
        return true;
    }
};
